// currency.tsp — model only, no HTTP imports
@friendlyName("BillingCurrencyToken")
model CurrencyToken {
  ...CurrencyBase<CurrencyType.Custom>;
  @visibility(Lifecycle.Create, Lifecycle.Read)
  code: CurrencyCodeCustom;
  @visibility(Lifecycle.Create, Lifecycle.Read)
  decimals: uint8;
}

// operations.tsp — HTTP decorators only here
interface CurrenciesTokenOperations {
  @extension(Shared.UnstableExtension, true)
  @extension(Shared.InternalExtension, true)
  @post
  @operationId("create-token-currency")
  @summary("Create token currency")
  create(
    @body body: Shared.CreateRequest<CurrencyToken>,
  ): Shared.CreateResponse<CurrencyToken> | Common.ErrorResponses;
}

// new-sub-resource.tsp (no HTTP imports)
import "../shared/index.tsp";
namespace Customers;

@friendlyName("BillingCustomerContract")
model CustomerContract {
  ...Shared.Resource;
  @visibility(Lifecycle.Create, Lifecycle.Read)
  title: string;
}

// operations.tsp addition
import "./new-sub-resource.tsp";
interface CustomerContractOperations {
  @get
  @operationId("get-customer-contract")
  @summary("Get customer contract")
  get(
    @path customerId: Shared.ULID,
    @path contractId: Shared.ULID,
  ): Shared.GetResponse<CustomerContract> | Common.NotFound | Common.ErrorResponses;

  @get
  @operationId("list-customer-contracts")
  @summary("List customer contracts")
  list(
    @path customerId: Shared.ULID,
    ...Common.PagePaginationQuery,
  ): Shared.PagePaginatedResponse<CustomerContract> | Common.ErrorResponses;
}

